// ❌ Prop drilling: tema passa por Header, depois Navbar, até chegar no Logo
function App() {
  return <Header tema="dark" />;
}
function Header({ tema }) {
  return <Navbar tema={tema} />;  // Header nem usa 'tema'!
}
function Navbar({ tema }) {
  return <Logo tema={tema} />;    // Navbar nem usa 'tema'!
}
function Logo({ tema }) {
  return <img className={tema} />; // só Logo precisa
}

import { createContext, useContext, useState } from 'react';

// 1. Criar o Context
const ThemeContext = createContext('light');

// 2. Prover o valor (no topo da árvore)
function App() {
  const [tema, setTema] = useState('dark');
  return (
    <ThemeContext.Provider value={tema}>
      <Header />
      <button onClick={() => setTema(t => t === 'dark' ? 'light' : 'dark')}>
        Trocar tema
      </button>
    </ThemeContext.Provider>
  );
}

// 3. Consumir em qualquer filho (sem prop drilling!)
function Logo() {
  const tema = useContext(ThemeContext);
  return <img className={tema} />;
}

