challenge.solution:
import { createContext, useContext } from 'react';

const UserContext = createContext({ nome: '', email: '' });

function UserInfo() {
  const { nome, email } = useContext(UserContext);
  return (
    <div>
      <h2>{nome}</h2>
      <p>{email}</p>
    </div>
  );
}

export default function App() {
  return (
    <UserContext.Provider value={{ nome: 'Maria', email: 'maria@email.com' }}>
      <div>
        <h1>Meu App</h1>
        <UserInfo />
      </div>
    </UserContext.Provider>
  );
}
